# -*- coding: utf-8 -*-
import csv

questions = [
  {"id":"4209","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Analitica","subtema":"Conicas — parabola","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A parabola de equacao y = x^2 - 4x + 3 tem vertice em:","alternativa_a":"(2, -1)","alternativa_b":"(4, 3)","alternativa_c":"(0, 3)","alternativa_d":"(-2, 15)","alternativa_e":"(1, 0)","resposta_correta":"a","explicacao":"Vertice: xv = -b/2a = -(-4)/(2x1) = 2. yv = (4ac-b^2)/4a = (4x1x3 - 16)/4 = (12-16)/4 = -4/4 = -1. Vertice em (2,-1).","resposta":""},
  {"id":"4210","tipo":"multipla","disciplina":"Matematica","tema":"Analise Combinatoria","subtema":"Principio multiplicativo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Um restaurante oferece 3 opcoes de entrada, 5 de prato principal e 2 de sobremesa. Quantos cardapios distintos podem ser formados?","alternativa_a":"30","alternativa_b":"10","alternativa_c":"60","alternativa_d":"15","alternativa_e":"25","resposta_correta":"a","explicacao":"Principio multiplicativo: 3 x 5 x 2 = 30 cardapios distintos.","resposta":""},
  {"id":"4211","tipo":"multipla","disciplina":"Matematica","tema":"Probabilidade","subtema":"Eventos compostos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Lancando dois dados, a probabilidade de obter soma 7 e:","alternativa_a":"1/6","alternativa_b":"1/12","alternativa_c":"7/36","alternativa_d":"1/36","alternativa_e":"6/36","resposta_correta":"a","explicacao":"Pares com soma 7: (1,6),(2,5),(3,4),(4,3),(5,2),(6,1) = 6 pares. Total de resultados: 6x6 = 36. P = 6/36 = 1/6.","resposta":""},
  {"id":"4212","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Poligonos regulares","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um poligono regular com 6 lados (hexagono regular) de lado 2 cm tem area:","alternativa_a":"6 raiz(3) cm2","alternativa_b":"12 cm2","alternativa_c":"24 cm2","alternativa_d":"3 raiz(3) cm2","alternativa_e":"18 cm2","resposta_correta":"a","explicacao":"Area do hexagono regular = (3*raiz(3)/2) * a^2 = (3*raiz(3)/2) * 4 = 6*raiz(3) cm2.","resposta":""},
  {"id":"4213","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Radiciacao","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O valor de raiz(4) + raiz(9) + raiz(25) e:","alternativa_a":"10","alternativa_b":"38","alternativa_c":"7","alternativa_d":"12","alternativa_e":"6","resposta_correta":"a","explicacao":"raiz(4) = 2; raiz(9) = 3; raiz(25) = 5. Soma = 2 + 3 + 5 = 10.","resposta":""},
  {"id":"4214","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Conservacao de energia mecanica","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um objeto de 2 kg cai de uma altura de 5 m. Sua velocidade ao chegar ao solo (g=10 m/s2, sem atrito) e:","alternativa_a":"10 m/s","alternativa_b":"20 m/s","alternativa_c":"5 m/s","alternativa_d":"100 m/s","alternativa_e":"50 m/s","resposta_correta":"a","explicacao":"Conservacao de energia: mgh = (1/2)mv^2 => v = raiz(2gh) = raiz(2x10x5) = raiz(100) = 10 m/s.","resposta":""},
  {"id":"4215","tipo":"multipla","disciplina":"Fisica","tema":"Eletricidade","subtema":"Potencia eletrica","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Uma lampada de 60 W, ligada durante 4 horas, consome uma energia de:","alternativa_a":"240 Wh = 0,24 kWh","alternativa_b":"15 Wh","alternativa_c":"60 kWh","alternativa_d":"240 kWh","alternativa_e":"4 Wh","resposta_correta":"a","explicacao":"E = P x t = 60 W x 4 h = 240 Wh = 0,24 kWh. A fatura de energia eletrica e calculada em kWh (quilowatt-hora).","resposta":""},
  {"id":"4216","tipo":"multipla","disciplina":"Fisica","tema":"Termodinamica","subtema":"Leis dos gases","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Mantendo a temperatura constante (processo isotermico), se a pressao de um gas dobra, seu volume:","alternativa_a":"Cai pela metade (Lei de Boyle)","alternativa_b":"Dobra","alternativa_c":"Permanece constante","alternativa_d":"Quadruplica","alternativa_e":"Cai a um quarto","resposta_correta":"a","explicacao":"Lei de Boyle-Mariotte: a temperatura constante, PV = constante. Se P dobra (P->2P), entao V deve cair a metade (V->V/2) para manter o produto constante: 2P x V/2 = PV.","resposta":""},
  {"id":"4217","tipo":"multipla","disciplina":"Fisica","tema":"Eletromagnetismo","subtema":"Transformadores","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um transformador tem 200 espiras no primario e 100 no secundario. Se a tensao primaria e 220 V, a tensao secundaria e:","alternativa_a":"110 V","alternativa_b":"440 V","alternativa_c":"220 V","alternativa_d":"55 V","alternativa_e":"100 V","resposta_correta":"a","explicacao":"V1/V2 = N1/N2 => 220/V2 = 200/100 => V2 = 220 x 100/200 = 110 V. Este e um transformador abaixador (step-down).","resposta":""},
  {"id":"4218","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Reacoes de precipitacao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A reacao AgNO3 + NaCl -> AgCl + NaNO3 e uma reacao de:","alternativa_a":"Dupla troca (precipitacao) — AgCl e insolavel","alternativa_b":"Simples troca (deslocamento)","alternativa_c":"Sintese (combinacao)","alternativa_d":"Decomposicao (analise)","alternativa_e":"Combustao","resposta_correta":"a","explicacao":"Dupla troca (ou metathese): dois compostos trocam seus ions/radicais. AgCl e insolavel em agua (precipitado branco) — e a base do teste qualitativo para ions cloreto. AgNO3 e NaCl sao soluveis; AgCl precipita.","resposta":""},
  {"id":"4219","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Cetonas e aldeidos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A acetona (propan-2-ona) e uma cetona. Cetonas diferem de aldeidos porque:","alternativa_a":"Nas cetonas a carbonila fica no carbono interno; nos aldeidos esta no carbono terminal","alternativa_b":"Cetonas tem formula molecular diferente dos aldeidos","alternativa_c":"Cetonas sao apolares e aldeidos sao polares","alternativa_d":"Aldeidos tem mais carbonos que cetonas","alternativa_e":"Cetonas reagem com oxigenio e aldeidos nao","resposta_correta":"a","explicacao":"O grupo carbonila (C=O): nos aldeidos, esta no carbono terminal da cadeia (pelo menos um H ligado ao carbono carbonilico): R-CHO. Nas cetonas, esta no carbono interno (sem H no carbono carbonilico): R-CO-R'. Exemplo: propanal (CH3CH2CHO) vs acetona (CH3COCH3).","resposta":""},
  {"id":"4220","tipo":"multipla","disciplina":"Quimica","tema":"Bioquimica","subtema":"Lipidios","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Os triglicerídeos sao formados pela uniao de:","alternativa_a":"Um glicerol e tres acidos graxos, por esterificacao","alternativa_b":"Tres moleculas de glicose","alternativa_c":"Aminoacidos e acidos graxos","alternativa_d":"Glicerol e fosfato","alternativa_e":"Tres moleculas de colesterol","resposta_correta":"a","explicacao":"Triglicerídeos (gorduras neutras) = glicerol (3C, 3 grupos OH) + 3 acidos graxos, ligados por ligacoes ester com perda de agua. Sao as principais moleculas de armazenamento de energia (gordura corporal). Os acidos graxos podem ser saturados (sem dupla ligacao, solidos a 25C — gordura animal) ou insaturados (com dupla ligacao, liquidos a 25C — oleos vegetais).","resposta":""},
  {"id":"4221","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema hormonal","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O hormonio ADH (hormonio antidiuretico ou vasopressina) atua nos:","alternativa_a":"Tubulos coletores do rim, aumentando a reabsorcao de agua e reduzindo a quantidade de urina","alternativa_b":"Pulmoes, controlando a frequencia respiratoria","alternativa_c":"Musculos cardiacos, aumentando os batimentos","alternativa_d":"Estomago, estimulando a producao de acido","alternativa_e":"Pancreas, estimulando a producao de insulina","resposta_correta":"a","explicacao":"O ADH (produzido no hipotalamo, liberado pela neurohipofise) atua nos tubulos coletores renais, aumentando a permeabilidade a agua e favorecendo sua reabsorcao. Reduz o volume de urina e aumenta sua concentracao. Deficiencia de ADH causa diabetes insipidus (urina muito diluida e abundante). O alcool inibe o ADH, causando desidratacao.","resposta":""},
  {"id":"4222","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Fluxo de materia e energia","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Ao contrario do fluxo de energia, o fluxo de materia num ecossistema e:","alternativa_a":"Ciclico — a materia circula entre seres vivos e ambiente (ciclos biogeoquimicos)","alternativa_b":"Unidirecional — a materia so entra e nunca sai","alternativa_c":"Linear — passa de nivel em nivel sem retorno","alternativa_d":"Nulo — a materia nao se move entre componentes","alternativa_e":"Proporcional a quantidade de energia disponivel","resposta_correta":"a","explicacao":"O fluxo de energia e unidirecional (entra como luz solar, sai como calor) — nao reciclavel. Ja o fluxo de materia e ciclico: os elementos quimicos (C, N, P, O, etc.) circulam nos ciclos biogeoquimicos entre seres vivos, solo, agua e atmosfera. Os decompositores sao fundamentais para devolver nutrientes ao ambiente abiotico.","resposta":""},
  {"id":"4223","tipo":"multipla","disciplina":"Biologia","tema":"Genetica","subtema":"Epigenetica","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A epigenetica estuda:","alternativa_a":"Modificacoes na expressao genica hereditarias que nao alteram a sequencia do DNA","alternativa_b":"Mutacoes na sequencia de DNA causadas por agentes quimicos","alternativa_c":"A relacao entre genes e proteinas","alternativa_d":"A duplicacao do DNA na divisao celular","alternativa_e":"O mapeamento do genoma humano","resposta_correta":"a","explicacao":"Epigenetica (epi = sobre) estuda modificacoes hereditarias na expressao genica que nao envolvem mudancas na sequencia de DNA. Mecanismos incluem: metilacao do DNA (silenciamento de genes), modificacao de histonas (condensacao da cromatina), RNA nao-codificante. Pode ser influenciada por ambiente, dieta e experiencias. Permite explicar como gemeos identicos (mesmo DNA) podem ter fenotipos diferentes.","resposta":""},
  {"id":"4224","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Questao ambiental global","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O Acordo de Paris (2015) sobre mudancas climaticas estabeleceu como meta:","alternativa_a":"Limitar o aquecimento global a 1,5-2 graus Celsius acima dos niveis pre-industriais","alternativa_b":"Reduzir a emissao de CFCs em 50%","alternativa_c":"Proibir a desmatamento na Amazonia","alternativa_d":"Criar um fundo de 1 trilhao de dolares para energias renovaveis","alternativa_e":"Estabelecer carbon tax universal de 50 dolares por tonelada","resposta_correta":"a","explicacao":"O Acordo de Paris (21a COP da ONU, Paris, dezembro de 2015) e um tratado internacional juridicamente vinculante que busca limitar o aumento da temperatura global a menos de 2 graus C (com esforcos para 1,5 graus C) em relacao aos niveis pre-industriais. Os paises apresentam Contribuicoes Determinadas Nacionalmente (NDCs) periodicamente revisadas.","resposta":""},
  {"id":"4225","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Desigualdade global","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O Indice de Desenvolvimento Humano (IDH) mais alto do mundo e encontrado principalmente em:","alternativa_a":"Paises escandinavos (Noruega, Suecia, Islandia) e paises de alta renda","alternativa_b":"Paises do Sul Global em desenvolvimento","alternativa_c":"Paises exportadores de petroleo","alternativa_d":"Paises mais populosos (China, India, Brasil)","alternativa_e":"Paises com maior territorio","resposta_correta":"a","explicacao":"Os paises com IDH muito alto (acima de 0,90) incluem Noruega, Islandia, Australia, Suecia, Irlanda, Alemanha, Hong Kong, entre outros. Esses paises combinam alta expectativa de vida, excelente sistema educacional e alta renda per capita. O Brasil tem IDH medio-alto (~0,76). Os paises com menor IDH sao principalmente africanos (Mali, Niger, Chade).","resposta":""},
  {"id":"4226","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Tecnologia e sociedade","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Quarta Revolucao Industrial (Industria 4.0) e caracterizada pela convergencia de:","alternativa_a":"Inteligencia artificial, Internet das Coisas, big data, impressao 3D e robotica avancada","alternativa_b":"Industria textil e maquinas a vapor","alternativa_c":"Eletricidade e producao em massa","alternativa_d":"Computadores pessoais e internet","alternativa_e":"Energia nuclear e aviacao","resposta_correta":"a","explicacao":"A Quarta Revolucao Industrial (termo cunhado por Klaus Schwab do Fórum de Davos) e a fusao de tecnologias fisicas, digitais e biologicas: IA, machine learning, IoT (Internet das Coisas), big data, computacao em nuvem, impressao 3D, nanotecnologia, biotecnologia, robotica e veiculos autonomos. Impacta profundamente o mercado de trabalho (automacao), a economia e a sociedade.","resposta":""},
  {"id":"4227","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"Pandemias","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A pandemia de COVID-19, declarada pela OMS em marco de 2020, foi causada por:","alternativa_a":"O virus SARS-CoV-2, que se originou na China em 2019","alternativa_b":"Uma bacteria resistente a antibioticos","alternativa_c":"Um virus influenza mutante","alternativa_d":"O virus HIV em nova variante","alternativa_e":"Poluicao atmosferica em nivel critico","resposta_correta":"a","explicacao":"A COVID-19 e causada pelo SARS-CoV-2 (Severe Acute Respiratory Syndrome Coronavirus 2), um coronavirus identificado em Wuhan, China, em dezembro de 2019. A OMS declarou pandemia em 11/03/2020. A doenca gerou uma crise sanitaria global com mais de 7 milhoes de mortes registradas. O desenvolvimento de vacinas em menos de um ano foi um marco cientifico historico.","resposta":""},
  {"id":"4228","tipo":"multipla","disciplina":"Geografia","tema":"Climatologia","subtema":"Biomas mundiais","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A floresta tropical umida (floresta equatorial) encontra-se principalmente em:","alternativa_a":"Amazonia (Brasil), Congo (Africa) e Sudeste Asiatico","alternativa_b":"Europa Ocidental e Leste dos EUA","alternativa_c":"Canada e Russia","alternativa_d":"Sahel africano e Caatinga brasileira","alternativa_e":"Australia e Nova Zelandia","resposta_correta":"a","explicacao":"As florestas tropicais umidas se localizam na faixa equatorial: Amazonia (maior floresta tropical do mundo, 5,5 mi km2 no Brasil), Bacia do Congo (Africa Central) e Sudeste Asiatico (Indonesia, Papua-Nova Guine, Borneo). Sao os ecossistemas de maior biodiversidade do planeta, com altissima precipitacao (>2000 mm/ano) e temperatura constante (~26C).","resposta":""},
  {"id":"4229","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Conjugacao verbal","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O verbo 'haver' no sentido de existir e impessoal. A forma correta e:","alternativa_a":"'Ha muitos problemas' (nao 'Haem muitos problemas')","alternativa_b":"'Haem muitos problemas'","alternativa_c":"'Ha muitas pessoas' e 'Haem muitas pessoas' — ambas corretas","alternativa_d":"'Haviam muitas pessoas na sala'","alternativa_e":"'Houveram muitos erros'","resposta_correta":"a","explicacao":"'Haver' no sentido de existir (= ter, existir) e sempre impessoal — fica na 3a pessoa do singular: 'Ha problemas', 'Havia pessoas', 'Houve erros'. Nao concorda com o substantivo que segue. Erro comum: 'Haviam problemas' ou 'Houveram erros'. O verbo 'ter' nesse sentido, na linguagem coloquial, pode ser pessoal: 'Tem problemas' (regional, informal).","resposta":""},
  {"id":"4230","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Cecilia Meireles","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Cecilia Meireles, poetisa da segunda fase modernista, e conhecida por uma lirica:","alternativa_a":"Espiritualizada, meditativa, com temas de efemeridade, morte e o impalpavel do tempo","alternativa_b":"Politica e combativa, de denuncia social","alternativa_c":"Erotic, sensorial e urbana","alternativa_d":"Regionalista, retratando o sertao nordestino","alternativa_e":"Humoristica e satirica","resposta_correta":"a","explicacao":"Cecilia Meireles (1901-1964) e uma das maiores poetas brasileiras. Sua lirica e marcada pela espiritualidade, efemeridade das coisas ('Ou isso ou aquilo'), meditacao sobre o tempo e a morte, musicalidade e imagismo. 'Romanceiro da Inconfidencia' e sua obra mais extensa (sobre Tiradentes). Diferentemente de Drummond (mais ironico e social), Cecilia tem tonalidade mais intimista e filosofica.","resposta":""},
  {"id":"4231","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Jorge Amado","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Jorge Amado, escritor baiano, ficou famoso por retratar em suas obras:","alternativa_a":"A cultura popular baiana, o povo negro, os marginalizados e o universo do candomble","alternativa_b":"A vida da aristocracia paulistana","alternativa_c":"O sertao cearense e a seca","alternativa_d":"A vida dos imigrantes japoneses no Brasil","alternativa_e":"A paisagem e o espirito do Rio Grande do Sul","resposta_correta":"a","explicacao":"Jorge Amado (1912-2001) e um dos escritores brasileiros mais lidos no mundo. Suas obras retratam a Bahia: pescadores, trabalhadores, mulheres negras, o candomble, o sincretismo religioso e a resistencia dos marginalizados. Obras famosas: 'Capitaes da Areia', 'Gabriela Cravo e Canela', 'Dona Flor e Seus Dois Maridos', 'Tenda dos Milagres'.","resposta":""},
  {"id":"4232","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Contemporanea","subtema":"Pos-modernidade","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Jean-Francois Lyotard define a pos-modernidade pela:","alternativa_a":"Incredulidade diante das meta-narrativas — rejeicao de sistemas de explicacao totalizadores","alternativa_b":"Celebracao da modernidade e da razao iluminista","alternativa_c":"Defesa do progresso cientifico e tecnologico","alternativa_d":"Retorno ao pensamento religioso e tradicional","alternativa_e":"Critica ao capitalismo por meio do materialismo historico","resposta_correta":"a","explicacao":"Em 'A Condicao Pos-Moderna' (1979), Lyotard define pos-modernidade como 'incredulidade diante das meta-narrativas' — os grandes sistemas de explicacao da modernidade (marxismo, iluminismo, progresso cientifico) perderam legitimidade. O saber pos-moderno e local, plural, contingente e performativo. Nao ha mais uma grande narrativa capaz de unificar o sentido da historia.","resposta":""},
  {"id":"4233","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Politica","subtema":"Republica em Platao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Na Republica de Platao, a organizacao ideal da cidade-estado (polis) seria governada pelos:","alternativa_a":"Filosofos-reis — aqueles que alcancariam o conhecimento das Formas (Ideias)","alternativa_b":"Guerreiros mais corajosos","alternativa_c":"Comerciantes mais ricos","alternativa_d":"Sacerdotes mais devotos","alternativa_e":"Cidadaos escolhidos por sorteio","resposta_correta":"a","explicacao":"Platao propoe que a polis ideal seria governada por filosofos que alcancariam o conhecimento da Forma do Bem (o Bem em si). A Alegoria da Caverna ilustra a jornada do filosofo ao conhecimento verdadeiro. A cidade ideal tem tres classes: produtores (virtude: moderacao), guardioes/guerreiros (virtude: coragem) e governantes-filosofos (virtude: sabedoria/prudencia). A justica e a harmonia entre as tres classes.","resposta":""},
  {"id":"4234","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Cultura","subtema":"Aculturacao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O conceito de aculturacao refere-se a:","alternativa_a":"Processo de contato entre culturas distintas que leva a mudancas em uma ou ambas","alternativa_b":"Transmissao cultural dentro de uma mesma sociedade","alternativa_c":"Perda total da cultura de origem","alternativa_d":"Criacao de uma cultura artificial pela midia","alternativa_e":"Imposicao forcada de uma cultura sobre outra","resposta_correta":"a","explicacao":"Aculturacao e o processo de contato e transferencia cultural entre grupos distintos. Pode resultar em: assimilacao (cultura minoritaria absorve a majoritaria), incorporacao (elementos sao adicionados sem perda da identidade), sincretismo (fusao de elementos de culturas distintas — ex: religioes afro-brasileiras) ou resistencia cultural. E diferente de endoculturacao (socializacao dentro da propria cultura).","resposta":""},
  {"id":"4235","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia Classica","subtema":"Consciencia de classe","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Para Marx, a diferenca entre 'classe em si' e 'classe para si' e:","alternativa_a":"'Em si' = posicao objetiva nas relacoes de producao; 'para si' = consciencia de seus interesses de classe","alternativa_b":"'Em si' = classe trabalhadora; 'para si' = burguesia","alternativa_c":"'Em si' = classe consciente; 'para si' = classe inconsciente","alternativa_d":"'Em si' = producao; 'para si' = consumo","alternativa_e":"'Em si' = capital constante; 'para si' = capital variavel","resposta_correta":"a","explicacao":"Marx distingue: 'classe em si' (Klasse an sich) = agrupamento objetivo de individuos que compartilham a mesma posicao nas relacoes de producao (ex: todos os trabalhadores), sem necessariamente terem consciencia disso. 'Classe para si' (Klasse fur sich) = quando a classe desenvolve consciencia de seus interesses comuns e se organiza politicamente para lutar por eles. A passagem de 'em si' para 'para si' e o processo de formacao de classe.","resposta":""},
  {"id":"4236","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Numeros primos","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Qual dos seguintes numeros e primo?","alternativa_a":"97","alternativa_b":"91","alternativa_c":"87","alternativa_d":"77","alternativa_e":"49","resposta_correta":"a","explicacao":"97 e primo (divisivel apenas por 1 e por ele mesmo). 91 = 7 x 13. 87 = 3 x 29. 77 = 7 x 11. 49 = 7 x 7.","resposta":""},
  {"id":"4237","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Equacoes biquadradas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As raizes da equacao x^4 - 5x^2 + 4 = 0 sao:","alternativa_a":"x = +/-1 e x = +/-2","alternativa_b":"x = +/-4 e x = +/-1","alternativa_c":"x = +/-5 e x = +/-4","alternativa_d":"x = 0 e x = +/-5","alternativa_e":"x = +/-2 e x = +/-4","resposta_correta":"a","explicacao":"Substituindo x^2 = y: y^2 - 5y + 4 = 0. Delta = 25 - 16 = 9. y = (5+/-3)/2: y1=4, y2=1. x^2=4 => x=+/-2; x^2=1 => x=+/-1.","resposta":""},
  {"id":"4238","tipo":"multipla","disciplina":"Fisica","tema":"Fisica Moderna","subtema":"Dual onda-particula","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A dualidade onda-particula, proposta por De Broglie, estabelece que:","alternativa_a":"Toda materia tem propriedades ondulatórias — seu comprimento de onda e lambda = h/mv","alternativa_b":"A luz e puramente uma onda eletromagnetica","alternativa_c":"Eletrons sao apenas particulas classicas","alternativa_d":"Fotons tem massa em repouso","alternativa_e":"Ondas mecanicas podem se propagar no vacuo","resposta_correta":"a","explicacao":"Louis de Broglie (1924, Nobel 1929) propôs que toda materia tem natureza dual onda-particula: lambda = h/p = h/(mv), onde h e a constante de Planck. Quanto maior o momento, menor o comprimento de onda. Eletrons tem comprimento de onda mensuravel (confirmado pela difracao de eletrons). Objetos macroscópicos tem lambda tao pequeno que o comportamento ondulatorio e impercebivel.","resposta":""},
  {"id":"4239","tipo":"multipla","disciplina":"Fisica","tema":"Fisica Moderna","subtema":"Principio da incerteza","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O Principio de Incerteza de Heisenberg afirma que:","alternativa_a":"Nao e possivel medir simultaneamente posicao e momento de uma particula com precisao arbitraria","alternativa_b":"O futuro de uma particula e completamente imprevisivel","alternativa_c":"A posicao de uma particula nao pode nunca ser conhecida","alternativa_d":"As particulas subatomicas nao obedecem as leis da termodinamica","alternativa_e":"O momento de uma particula e sempre nulo no estado fundamental","resposta_correta":"a","explicacao":"Heisenberg (1927): Delta_x * Delta_p >= h/(4*pi). A imprecisao na posicao (Delta_x) vezes a imprecisao no momento (Delta_p) e maior ou igual a h/4pi. Nao e limitacao instrumental, mas propriedade fundamental da natureza quantica. Quanto mais precisamente se mede a posicao, menos se sabe o momento, e vice-versa. Tem implicacoes profundas para a fisica quantica e o determinismo.","resposta":""},
  {"id":"4240","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Terpenos e essencias","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Os terpenos sao compostos organicos encontrados em plantas, responsaveis por aromas. Eles sao polimeros de:","alternativa_a":"Isopreno (2-metilbutadieno) — CH2=C(CH3)-CH=CH2","alternativa_b":"Glicose","alternativa_c":"Aminoacidos","alternativa_d":"Acidos graxos","alternativa_e":"Nucleotideos","resposta_correta":"a","explicacao":"Os terpenos sao biossintetizados a partir de unidades de isopreno (C5H8). Monoterpenos (C10): mentol, limoneno. Sesquiterpenos (C15): beta-carofeno. Diterpenos (C20): vitamina A. Triterpenos (C30): colesterol (precursor). Tetraterpenos (C40): beta-caroteno. A borracha natural e um politerpeno (poliisopreno). Muitos terpenos tem atividade farmacologica (artemisinina, taxol).","resposta":""},
  {"id":"4241","tipo":"multipla","disciplina":"Biologia","tema":"Citologia","subtema":"Nucleo celular","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A funcao principal do nucleo celular e:","alternativa_a":"Conter e proteger o DNA e controlar as atividades celulares","alternativa_b":"Produzir energia na forma de ATP","alternativa_c":"Sintetizar lipidios e processar proteinas","alternativa_d":"Realizar a digestao intracelular","alternativa_e":"Controlar a entrada e saida de substancias","resposta_correta":"a","explicacao":"O nucleo e delimitado pela carioteca (envoltorio nuclear com poros nucleares). Contem a cromatina (DNA + histonas) que constitui os cromossomos na divisao celular. E o 'centro de controle' da celula: o DNA contem as instrucoes (genes) para a sintese de proteinas e todas as atividades celulares. O nucleolo produz rRNA e e o local de montagem dos ribossomos.","resposta":""},
  {"id":"4242","tipo":"multipla","disciplina":"Biologia","tema":"Botanica","subtema":"Briofitas e pteridofitas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As briofitas (musgos, hepáticas) diferem das pteridofitas (samambaias) principalmente por:","alternativa_a":"Briofitas nao possuem tecido vascular (xilema/floema) e sao menores; pteridofitas sao vascularizadas","alternativa_b":"Pteridofitas produzem flores e sementes; briofitas nao","alternativa_c":"Briofitas vivem apenas em ambientes marinhos","alternativa_d":"Pteridofitas nao realizam fotossintese","alternativa_e":"Briofitas sao maiores e mais complexas que pteridofitas","resposta_correta":"a","explicacao":"Briofitas (Bryophyta) sao plantas avasculares: sem xilema/floema, portanto sem conducao eficiente de agua — ficam pequenas e dependentes de ambientes umidos. Pteridofitas (Pteridophyta) sao as primeiras plantas vasculares (tracheophytes), com xilema e floema, permitindo maior porte. Nem briofitas nem pteridofitas produzem sementes (sao criptogamas). As espermatofitas (gimnospermas e angiospermas) produzem sementes.","resposta":""},
  {"id":"4243","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Feudalismo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O feudalismo, sistema socioeconomico da Europa Medieval, baseava-se em:","alternativa_a":"Relacoes de suserania e vassalagem — servidao dos camponeses em troca de protecao","alternativa_b":"Comercio livre entre cidades autonomas","alternativa_c":"Modo de producao capitalista com salario","alternativa_d":"Escravidao como base da producao","alternativa_e":"Democracia direta nas aldeias","resposta_correta":"a","explicacao":"O feudalismo (seculos IX-XIII) baseava-se na relacao entre suzerano (senhor que concede o feudo) e vassalo (nobre que recebe e presta fidelidade) e na servidao dos camponeses (servos da gleba), presos a terra em troca de protecao militar. Era uma sociedade estamental (clero, nobreza e servos/povo), com economia agricola autossuficiente, descentralizacao politica e poder da Igreja Catolica.","resposta":""},
  {"id":"4244","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Renascimento Cientifico","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Galileu Galilei e considerado o 'pai da ciencia moderna' porque:","alternativa_a":"Desenvolveu o metodo cientifico empirico — observacao, experimentacao e matematizacao da natureza","alternativa_b":"Inventou o telescopio e descobriu a America","alternativa_c":"Propôs a teoria da evolucao das especies","alternativa_d":"Calculou a distancia da Terra ao Sol","alternativa_e":"Formulou as leis da gravitacao universal","resposta_correta":"a","explicacao":"Galileu (1564-1642) revolucionou a ciencia ao defender que a natureza e escrita em linguagem matematica e que o conhecimento cientifico deve basear-se na observacao e no experimento — nao em autoridades (Aristoteles) ou textos sagrados. Melhorou o telescopio e usou-o para confirmar o heliocentrismo (luas de Jupiter, fases de Venus). Foi julgado pela Inquisicao por defender o copernicanismo.","resposta":""},
  {"id":"4245","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Nacoes e nacionalismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O nacionalismo como ideologia politica emergiu principalmente:","alternativa_a":"No final do seculo XVIII e inicio do XIX, impulsionado pelas revolucoes francesa e americana","alternativa_b":"Na Idade Media, com as cruzadas","alternativa_c":"Na Antiguidade Classica, com as cidades-estado gregas","alternativa_d":"Apos a Segunda Guerra Mundial","alternativa_e":"Com a Reforma Protestante do seculo XVI","resposta_correta":"a","explicacao":"O nacionalismo moderno emergiu com a Revolucao Francesa (soberania popular associada a nacao, nao ao rei) e se espalhou pela Europa e Americas no seculo XIX. As guerras napoleonicas paradoxalmente difundiram o nacionalismo ao suscitar resistencias nacionais. As revolucoes liberais de 1848 buscaram a unidade nacional (Italia, Alemanha). O Romantismo cultural revalorizou linguas e culturas nacionais.","resposta":""},
  {"id":"4246","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Canudos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Guerra de Canudos (1896-1897), retratada por Euclydes da Cunha em 'Os Sertoes', foi um conflito entre:","alternativa_a":"O exercito republicano e uma comunidade sertaneja liderada por Antonio Conselheiro, no interior da Bahia","alternativa_b":"Tropas imperiais e republicanas pelo controle do sertao","alternativa_c":"Jaguncos e coroneis nordestinos","alternativa_d":"Trabalhadores rurais e latifundiarios","alternativa_e":"Indios e colonos pela posse da terra","resposta_correta":"a","explicacao":"Canudos era uma comunidade de sertanejos pobres, liderada por Antonio Conselheiro (lider mistico e carismatico), que rejeitava a Republica e seus impostos. Chegou a ter 25.000-30.000 habitantes. O governo republicano enviou quatro expedicoes militares (as tres primeiras foram derrotadas) e destruiu o arraial em outubro de 1897, com massacre praticamente total dos habitantes. Euclydes da Cunha imortalizou o conflito em 'Os Sertoes' (1902).","resposta":""},
  {"id":"4247","tipo":"multipla","disciplina":"Geografia","tema":"Populacao","subtema":"Urbanizacao no mundo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A maioria da populacao mundial passou a viver em areas urbanas pela primeira vez em:","alternativa_a":"2007-2008, segundo dados da ONU","alternativa_b":"1950, apos a Segunda Guerra Mundial","alternativa_c":"1980, com a globalizacao","alternativa_d":"2020, apos a pandemia","alternativa_e":"1900, com a industrializacao","resposta_correta":"a","explicacao":"Segundo a ONU, em 2007-2008 a populacao urbana mundial ultrapassou pela primeira vez a rural. Atualmente ~56% da populacao mundial vive em cidades, com projecao de 68% em 2050. O crescimento urbano e mais rapido nos paises em desenvolvimento (Africa e Asia), enquanto os paises desenvolvidos ja sao predominantemente urbanos ha decadas.","resposta":""},
  {"id":"4248","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Erros comuns — cecê e se","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A forma correta da frase e:","alternativa_a":"'Mais vale um passaro na mao do que dois voando'","alternativa_b":"'Mais vale um passaro na mao do que dois voando' e 'Mas vale...'","alternativa_c":"'Mais vale' e 'mas vale' sao equivalentes nessa expressao","alternativa_d":"'Mas vale...' e a forma correta","alternativa_e":"A expressao nao existe na lingua portuguesa","resposta_correta":"a","explicacao":"'Mais vale' e o correto — 'mais' aqui indica superioridade/comparacao (advérbio de intensidade), nao adversidade. 'Mas' e conjuncao adversativa (= porem, entretanto). Outros casos confusos: 'a princípio' (no inicio) vs 'em princípio' (teoricamente); 'mau' (adjetivo) vs 'mal' (adverb/substantivo); 'ha' (verbo ter/existir) vs 'a' (preposicao/artigo).","resposta":""},
  {"id":"4249","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Clarice Lispector","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Clarice Lispector, uma das maiores escritoras brasileiras do seculo XX, ficou conhecida por uma prosa:","alternativa_a":"Introspectiva, lirica, que explora o fluxo de consciencia e a experiencia interior das personagens","alternativa_b":"Realista e documentaria, retratando favelados","alternativa_c":"Comica e satirica, criticando a burguesia","alternativa_d":"Historica, narrando episodios da colonizacao","alternativa_e":"Regionalista, focada no nordeste brasileiro","resposta_correta":"a","explicacao":"Clarice Lispector (1920-1977) revolucionou a prosa brasileira com sua escrita introspectiva e fenomenologica. Obras como 'A Paixao Segundo G.H.', 'A Maca no Escuro' e 'A Hora da Estrela' exploram o fluxo de consciencia, a crise existencial, a busca pelo 'ser' e a experiencia do eu feminino. Sua linguagem e experimental, poetica e filosofica. Uma das grandes escritoras da literatura mundial.","resposta":""},
  {"id":"4250","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Contemporanea","subtema":"Hermeneutica","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A hermeneutica filosofica de Hans-Georg Gadamer propoe que a compreensao de textos envolve:","alternativa_a":"A fusao de horizontes — o horizonte do leitor e o do texto se fundem num novo significado","alternativa_b":"A reproducao fiel da intencao original do autor","alternativa_c":"A desconstrucao sistematica dos pressupostos do texto","alternativa_d":"A analise logica das proposicoes do texto","alternativa_e":"A eliminacao do contexto historico para captar o sentido universal","resposta_correta":"a","explicacao":"Gadamer, em 'Verdade e Metodo' (1960), propoe que a compreensao e sempre historicamente situada — o leitor traz seus preconceitos e horizonte cultural. Ao interpretar um texto, ocorre a 'fusao de horizontes' (Horizontverschmelzung): o horizonte do leitor e o do texto se fundem, gerando um novo significado. A compreensao e sempre uma recriacao, nao uma reproducao neutra. O 'circulo hermeneutico' descreve a relacao parte-todo na interpretacao.","resposta":""},
  {"id":"4251","tipo":"multipla","disciplina":"Filosofia","tema":"Etica","subtema":"Etica do cuidado","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A etica do cuidado, associada a Carol Gilligan e Nel Noddings, enfatiza:","alternativa_a":"As relacoes de cuidado, responsabilidade e empatia como base da moralidade","alternativa_b":"A imparcialidade e universalidade das regras morais","alternativa_c":"A maximizacao do bem-estar do maior numero","alternativa_d":"O dever absoluto independente das consequencias","alternativa_e":"A virtude individual como unico fundamento moral","resposta_correta":"a","explicacao":"A etica do cuidado emergiu como critica as eticas tradicionais (kantiana, utilitarista) que privilegiam a autonomia, a justica e a imparcialidade. Gilligan, em 'In a Different Voice' (1982), argumenta que as mulheres desenvolvem uma orientacao moral baseada em cuidado, relacionamentos e responsabilidade concreta com os outros — diferente da moralidade abstrata de Kohlberg. Relevante para bioética, enfermagem e politicas sociais.","resposta":""},
  {"id":"4252","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Arte","subtema":"Arte e sociedade","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Para Arnold Hauser, a arte e:","alternativa_a":"Um fenomeno social — produto e reflexo das condicoes sociais, economicas e historicas de cada epoca","alternativa_b":"Uma expressao puramente individual e subjetiva","alternativa_c":"Uma atividade tecnica sem determinacoes sociais","alternativa_d":"Uma forma de evasao da realidade social","alternativa_e":"Exclusivamente um produto da elite culta","resposta_correta":"a","explicacao":"Arnold Hauser, em 'Historia Social da Arte e da Literatura' (1951), analisa a arte como fenomeno social: as formas artisticas refletem e reproduzem as relacoes sociais, economicas e politicas de cada periodo. A arte renascentista reflete o humanismo burgues; o barroco, o absolutismo e a Contra-Reforma; o Realismo do seculo XIX, a classe trabalhadora industrial. A historia da arte e inseparavel da historia social.","resposta":""},
  {"id":"4253","tipo":"multipla","disciplina":"Sociologia","tema":"Teoria Critica","subtema":"Escola de Frankfurt","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A Teoria Critica da Escola de Frankfurt (Horkheimer, Adorno, Marcuse) diferencia-se da teoria tradicional por:","alternativa_a":"Nao pretender neutralidade — compromete-se com a emancipacao humana e a critica da dominacao","alternativa_b":"Defender a neutralidade axiologica da ciencia","alternativa_c":"Rejeitar qualquer influencia do marxismo","alternativa_d":"Apoiar o positivismo logico do Circulo de Viena","alternativa_e":"Defender a psicanalise como ciencia exata","resposta_correta":"a","explicacao":"Horkheimer distinguiu teoria tradicional (pretende neutralidade, descreve o existente) da teoria critica (assume compromisso normativo com a emancipacao). A Escola de Frankfurt integra Marx, Freud e Hegel para analisar as formas de dominacao na sociedade capitalista avancada (ideologia, industria cultural, autoritarismo). O projeto critico visa identificar as possibilidades de transformacao social reprimidas pela ordem vigente.","resposta":""},
  {"id":"4254","tipo":"multipla","disciplina":"Matematica","tema":"Algebra Linear","subtema":"Vetor e produto escalar","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O produto escalar entre os vetores u = (3, 4) e v = (1, -2) e:","alternativa_a":"-5","alternativa_b":"5","alternativa_c":"3","alternativa_d":"-3","alternativa_e":"0","resposta_correta":"a","explicacao":"Produto escalar: u.v = 3x1 + 4x(-2) = 3 - 8 = -5.","resposta":""},
  {"id":"4255","tipo":"multipla","disciplina":"Matematica","tema":"Calculo","subtema":"Regra da cadeia","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A derivada de f(x) = (2x+1)^3 e:","alternativa_a":"6(2x+1)^2","alternativa_b":"3(2x+1)^2","alternativa_c":"6(2x+1)","alternativa_d":"(2x+1)^2","alternativa_e":"2(2x+1)^3","resposta_correta":"a","explicacao":"Regra da cadeia: f'(x) = 3(2x+1)^2 * 2 = 6(2x+1)^2.","resposta":""},
  {"id":"4256","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Simples Harmonico","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"No Movimento Harmonico Simples (MHS), a aceleracao do oscilador e:","alternativa_a":"Proporcional ao deslocamento e oposta a ele (a = -omega^2 * x)","alternativa_b":"Constante e positiva","alternativa_c":"Proporcional a velocidade","alternativa_d":"Nula em todo momento","alternativa_e":"Maxima no ponto de equilíbrio","resposta_correta":"a","explicacao":"No MHS: a = -omega^2 * x (omega = frequencia angular). A aceleracao e maxima nos extremos (|x| maximo) e nula no ponto de equilibrio. A velocidade e nula nos extremos e maxima no equilibrio. E um movimento periodico onde a forca restauradora e proporcional ao deslocamento (Lei de Hooke para mola, pendulo simples para pequenos angulos).","resposta":""},
  {"id":"4257","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Solucoes tampao","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Uma solucao tampao e capaz de:","alternativa_a":"Resistir a grandes variacoes de pH ao adicionar pequenas quantidades de acido ou base","alternativa_b":"Neutralizar completamente qualquer quantidade de acido","alternativa_c":"Manter pH = 7 em qualquer circunstancia","alternativa_d":"Amplificar o efeito de acidos fortes","alternativa_e":"Precipitar ions metalicos em solucao","resposta_correta":"a","explicacao":"Uma solucao tampao (buffer) e composta por um acido fraco e seu sal conjugado (ou uma base fraca e seu sal). Resiste a mudancas de pH: quando um acido e adicionado, a base conjugada o neutraliza; quando uma base e adicionada, o acido fraco a neutraliza. Exemplos biologicos: tampao carbonato/bicarbonato no sangue (pH ~7,4); tampao fosfato nas celulas.","resposta":""},
  {"id":"4258","tipo":"multipla","disciplina":"Biologia","tema":"Genetica","subtema":"Teoria cromossomica da heranca","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A teoria cromosomica da heranca, desenvolvida por Sutton e Morgan, estabelece que:","alternativa_a":"Os genes estao localizados nos cromossomos e seguem os padroes de segregacao de Mendel","alternativa_b":"Os genes estao dispersos no citoplasma da celula","alternativa_c":"Os cromossomos sao compostos apenas de proteinas","alternativa_d":"A heranca e exclusivamente materna","alternativa_e":"Os genes funcionam independente dos cromossomos","resposta_correta":"a","explicacao":"Walter Sutton (citologista) e Theodor Boveri (embriologista) perceberam independentemente (1902-03) que os cromossomos comportam-se nas divisoes celulares exatamente como os 'fatores hereditarios' de Mendel. Morgan confirmou com experimentos em Drosophila: genes estao nos cromossomos, genes ligados no mesmo cromossomo sao herdados juntos, crossing-over separa genes ligados. Fundou a genetica experimental moderna.","resposta":""},
]

